const sismosReales = [
  {
    "codigo": "2026-0290",
    "fecha_local": "2026-05-19",
    "hora_local": "17:57:51",
    "latitud": -14.42,
    "longitud": -75.83,
    "magnitud": 6.1,
    "referencia": "41 km al S de Ica, Ica - Ica"
  },
  {
    "codigo": "2026-0253",
    "fecha_local": "2026-05-05",
    "hora_local": "15:58:25",
    "latitud": -3.56,
    "longitud": -80.61,
    "magnitud": 5.0,
    "referencia": "13 km al NE de Zorritos, Contralmirante Villar - Tumbes"
  }
];

return sismosReales.map(sismo => {
  const magn = parseFloat(sismo.magnitud);
  const lat = parseFloat(sismo.latitud);
  const lon = parseFloat(sismo.longitud);

  // 1. Asignación de Severidad Numérica
  let sevNumerica = 3;
  if (magn < 4.5) sevNumerica = 1;
  else if (magn >= 4.5 && magn < 6.0) sevNumerica = 3;
  else if (magn >= 6.0) sevNumerica = 5;

  // 2. Dinamismo Ciberfísico: El radio del polígono depende de la magnitud
  // Sismo 6.1 tendrá un radio de ~15km (0.15 grados), sismo 5.0 tendrá ~8km (0.08 grados)
  const radio = magn >= 6.0 ? 0.15 : 0.08;

  // 3. Construimos un cuadrado (POLYGON) cerrando el anillo en el primer punto
  const minLat = lat - radio;
  const maxLat = lat + radio;
  const minLon = lon - radio;
  const maxLon = lon + radio;

  const polygonWKT = `POLYGON((${minLon} ${minLat}, ${maxLon} ${minLat}, ${maxLon} ${maxLat}, ${minLon} ${maxLat}, ${minLon} ${minLat}))`;

  return {
    json: {
      id_evento: sismo.codigo,
      tipo_desastre: 'SISMO',
      severidad: sevNumerica,
      descripcion: `Sismo de magnitud ${magn} M_w - ${sismo.referencia}`,
      geometria_wkt: polygonWKT,
      fecha_evento: `${sismo.fecha_local}T${sismo.hora_local}`
    }
  };
});
